var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"복수귀, 알레이스터.","JPN":"復讐鬼、アレイスター。","ENG":"The Revenger, Aleister.","TWN":"復仇之鬼，阿萊斯特。"},"stage":{"bg":"SWANSONG_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그게 내가 이 무대에서 정한 배역의 이름이야.","JPN":"それが私がこの舞台で決めた配役の名前だ。","ENG":"That is the name of the role I've given myself for this stage.","TWN":"那是我在這個舞台上定下的角色名字。"},"stage":{"bg":"SWANSONG_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"알레이스터……?","JPN":"アレイスター……？","ENG":"Aleister...?","TWN":"阿萊斯特……？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제 포기하게, 카넬리안.","JPN":"ここで諦めたまえ、カーネリアン。","ENG":"Give up, Carnelian.","TWN":"現在放棄吧，卡內利安。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"삼 년 전, 런던에서 발생한 그림자 사태는 다름 아닌 우리의 실책이었어.","JPN":"三年前、ロンドンで発生したシャドウ事変は、他でもない私たちの失敗だった。","ENG":"The Shadow incident in London three years ago was our mistake.","TWN":"三年前，倫敦發生的暗影事件，正是我們的失誤。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"조금만 더 일찍 모든 것을 깨달았다면, 자네의 동생을 구해낼 수 있었을지도 모르지","JPN":"もう少し早くすべてのことに気付いていたなら、君の妹を救うことができたのかもしれない。","ENG":"If we had realized what was happening sooner, we could've saved your sister.","TWN":"如果能早一點察覺到一切，或許還能救出你的妹妹。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이미 소중한 사람을 잃어버린 자네에게는 변명처럼 들릴 지도 몰라.","JPN":"すでに大事な人を失してしまった君には、言い訳にしか聞こえないだろう。","ENG":"I know it might sound like an excuse to someone who had lost someone dear.","TWN":"對於已經失去珍貴之人的你來說，這聽起來可能像是藉口。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 우린 그 사태의 흑막을 밝혀내기 위해 모든 수단을 동원하여 최선을 다했네.","JPN":"だが、私たちはあの事変の黒幕を突き止めるためにあらゆる手段を使って頑張ってきた。","ENG":"But we did our best to uncover who was behind it all.","TWN":"但是為了揭開那次案件的幕後黑手，我們動用了所有手段，盡了最大的努力。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 파트너는 이를 위해, 지난 삼 년간 그의 밑에서 손을 더럽혔어.","JPN":"私のパートナーはそのために、三年間彼の下で手を汚したのだ。","ENG":"And for this, my partner here had gotten his hands dirty for the past three years.","TWN":"我的搭檔為了這個目的，過去三年一直在他手下幹髒活。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티…….","JPN":"モリアーティ……","ENG":"Moriarty...","TWN":"莫里蒂……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 그 사건의 배후에는 모리어티 교수가 있었어.","JPN":"そう。あの事件の裏にはモリアーティ教授がいた。","ENG":"Yes. It was Professor Moriarty who was behind it.","TWN":"是的。那起事件的幕後黑手是莫里蒂教授。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"대체 어째서 그자의 말을 따랐던 거지?","JPN":"いったいどうして彼の指示に従ったのだ？","ENG":"So, why did you choose to follow his orders?","TWN":"到底為什麼要聽那傢伙的話？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그자는 자네의 동생을 마물로 만든 장본인이나 다름이 없을 텐데?","JPN":"あの者は君の妹を魔物にした張本人同然なはずだが。","ENG":"He is the one responsible for turning your sister into a monster.","TWN":"那個人不就是把你妹妹變成怪物的罪魁禍首嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"……나도 알고 있어.","JPN":"……私だってわかっている。","ENG":"...I know.","TWN":"……我也知道這些。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 나의 계시를 실현하기 위해서는 반드시 그자의 협력이 필요했지.","JPN":"でも、私の啓示を実現するためには必ずモリアーティの協力が必要だったんだ。","ENG":"But I needed his help in actualizing my revelation.","TWN":"但是為了實現我得到的啟示，必須要有那個人的協助。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"오히려 그자는 자기 목숨에 대한 집착이 전혀 없었어.","JPN":"むしろ、彼は自分の命にまったく執着していなかった。","ENG":"He had no obsession with his life, after all.","TWN":"那個人反而對自己的生命毫不執著。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.</color>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>行汝欲行之事，此為律法之全部。</color>"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 자네도 알고 있을 텐데, 숙적?","JPN":"君もわかっているはずだろう、宿敵？","ENG":"I’m sure you know this too, my nemesis.","TWN":"所以你也明白的，對吧，宿敵？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"내가 진짜 원하는 것은 나의 하찮은 목숨의 보전 따위가 아니라는 걸 말이야.","JPN":"私が本当に望むものとは、たかが自分の命を守るなどのくだらないものではないということを。","ENG":"What I truly want is not preserving my worthless life.","TWN":"我真正想要的並不是保全我這卑微的性命。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그자가 원하는 바는 단 하나.","JPN":"モリアーティの望みはたった一つ。","ENG":"There was only one thing he wanted.","TWN":"那傢伙的願望只有一個。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"이 땅에 <color=#ffd34c>천사</color>를 강림시켜, 황금 새벽을 맞이하는 것.","JPN":"この地に<color=#ffd34c>天使</color>を降臨させて、黄金の暁を迎えること。","ENG":"The descending of an <color=#ffd34c>angel</color> to this world, and welcoming the golden dawn.","TWN":"讓<color=#ffd34c>天使</color>降臨這片土地，迎接黃金黎明。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"오직 그것만이 그자의 법이었지.","JPN":"ただそれだけが、モリアーティの法だった。","ENG":"That was his only law.","TWN":"那就是他唯一的律法。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"의식을 마치면, 그자는 순순히 자기 목숨을 내놓겠다고 하더군.","JPN":"儀式が終われば、彼は素直に自分の命を捧げると言っていたんだ。","ENG":"After completing the ritual, he said that he would willingly give up his life.","TWN":"儀式結束後，他說會乖乖交出自己的性命。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"덕분에 나는 그자의 부와 명예, 조직 그리고 지식을 이용할 수 있었어.","JPN":"おかげで私は彼の富と名誉、組織、そして知識を利用することができた。","ENG":"Thanks to that, I was able to take advantage of his wealth, fame, organization, and knowledge.","TWN":"多虧了他，我才能利用他的財富、名譽、組織和知識。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"동생을 모욕하던 이 썩어빠진 도시에 복수를 이뤄낼 수 있었고.","JPN":"妹を侮辱したこのクソみたいな都市に、復讐することができた。","ENG":"I was able to get my revenge on this rotten city that had insulted my sister.","TWN":"我才能對這個玷污了我妹妹的腐敗之城進行復仇。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};